1	type Quote = { premium: number };
2	
3	const PROCESSING_FEE = 5;
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	const basePremiumFor = (item: { type: string }): number =>
10	  BASE_PREMIUM_BY_TYPE[item.type];
11	
12	export const quote = (input: { items: Array<{ type: string }> }): Quote => {
13	  const itemsTotal = input.items.reduce(
14	    (sum, item) => sum + basePremiumFor(item),
15	    0,
16	  );
17	  return { premium: itemsTotal + PROCESSING_FEE };
18	};
19	
20	export const claim = (_input: unknown): unknown => {
21	  return undefined;
22	};
